#include <stdio.h>
#include <stdlib.h>

int main() {
    int T; if (scanf("%d", &T)!=1) return 0;
    while (T--) {
        int N; scanf("%d", &N);
        int total = 2 * N;
        int oddCnt = 0;
        for (int i = 0; i < total; ++i) {
            int x; scanf("%d", &x);
            if (x & 1) oddCnt++;
        }
        if (oddCnt % 2 == 0) printf("YES\n");
        else printf("NO\n");
    }
    return 0;
}

