#!/usr/bin/env python3
import sys

def solve():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out_lines = []
    for _ in range(T):
        N = int(next(it))
        odd_cnt = 0
        for _ in range(2 * N):
            x = int(next(it))
            if x & 1:
                odd_cnt += 1
        out_lines.append('YES' if odd_cnt % 2 == 0 else 'NO')
    sys.stdout.write('\n'.join(out_lines))

if __name__ == "__main__":
    solve()

